import{_ as r,c as t,o as e,d as s}from"./app.de5d70b2.js";var p="/assets/qy3zQ5f-OCo.0ce3b383.jpg",o="/assets/C8ozxY14JBA.298b83b2.jpg",n="/assets/ekez05xgmnA.4de0d5a1.jpg",g="/assets/VUAAS6CeAO4.02f32eef.jpg",a="/assets/t677HiywbaU.2a17c2ba.jpg",i="/assets/2I1Fy7euH4Q.85def8e5.jpg",_="/assets/t42BIo6hQZY.f3ac1339.jpg";const x='{"title":"\u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044F \u2014 \u043D\u0435\u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u0433\u0430\u0440\u0430\u0436 \u043D\u0430 \u043F\u0440\u043E\u0441\u043F\u0435\u043A\u0442\u0435","description":"","frontmatter":{"title":"\u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044F \u2014 \u043D\u0435\u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u0433\u0430\u0440\u0430\u0436 \u043D\u0430 \u043F\u0440\u043E\u0441\u043F\u0435\u043A\u0442\u0435","date":"2018-05-14","cover":"cover.jpg"},"headers":[],"relativePath":"theory/repost/bikekitchen-by/index.md"}',c={},l=s('<blockquote><p><a href="http://onetimer.by/News/Article/VeloKukhnya-neobychnyy-garazh-na-prospekte" class="external-link" target="_blank" rel="noopener noreferrer">OneTimer.by</a>\xA0\u043F\u043E\u0431\u044B\u0432\u0430\u043B \u0432 \u0433\u043E\u0441\u0442\u044F\u0445 \u0443 \u043F\u0440\u043E\u0435\u043A\u0442\u0430\xA0<a href="http://bikekitchen.by/be" class="external-link" target="_blank" rel="noopener noreferrer">\xAB\u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044F\xBB</a>. \u0421\u043F\u0440\u043E\u0441\u0438\u0442\u0435, \u0430 \u0447\u0442\u043E \u044D\u0442\u043E \u0437\u0430 \u043F\u0440\u043E\u0435\u043A\u0442? \u0415\u0441\u043B\u0438 \u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u0437\u0430\u0443\u043C\u043D\u044B\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0442\u043E \u044D\u0442\u043E \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0433\u0430\u0440\u0430\u0436, \u0433\u0434\u0435 \u0434\u0435\u0436\u0443\u0440\u044F\u0442 \u0432\u043E\u043B\u043E\u043D\u0442\u0435\u0440\u044B \u0438 \u043A\u0443\u0434\u0430 \u043C\u043E\u0433\u0443\u0442 \u043F\u0440\u0438\u0439\u0442\u0438 \u0432\u0441\u0435 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u043F\u043E\u0447\u0438\u043D\u0438\u0442\u044C \u0441\u0432\u043E\u0435\u0433\u043E \xAB\u0436\u0435\u043B\u0435\u0437\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u044F\xBB \u043B\u0438\u0431\u043E \u0441\u043E\u0431\u0440\u0430\u0442\u044C \u043D\u043E\u0432\u044B\u0439!</p></blockquote><p>\u0412\u0447\u0435\u0440\u0430 \u043D\u0430\u043C \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u043F\u043E\u043E\u0431\u0449\u0430\u0442\u044C\u0441\u044F \u0441 \u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u043C \u0434\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430\xA0<strong>\u0414\u0436\u043E\u043D\u043E\u043C \u0420\u043E\u0441\u043C\u044D\u043D\u043E\u043C</strong>. \u0421\u0430\u043C \u0414\u0436\u043E\u043D \u0440\u043E\u0434\u043E\u043C \u0438\u0437 \u041D\u044C\u044E-\u0419\u043E\u0440\u043A\u0430, \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0436\u0438\u043B \u0432 \u0420\u043E\u0441\u0441\u0438\u0438 \u0438 \u0432\u043E\u0442 \u0443\u0436\u0435 9 \u043B\u0435\u0442 \u0436\u0438\u0432\u0435\u0442 \u0432 \u0411\u0435\u043B\u0430\u0440\u0443\u0441\u0438. 63-\u043B\u0435\u0442\u043D\u0438\u0439 \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u044C \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043E\u0432 \u043E\u0442\u043B\u0438\u0447\u043D\u043E \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u0438 \u043D\u0438 \u043C\u0438\u043D\u0443\u0442\u044B \u043D\u0435 \u0441\u043E\u043C\u043D\u0435\u0432\u0430\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u044D\u0442\u043E \u0432\u0441\u0435 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0443.</p><p><img src="'+p+'" alt=""></p><p><strong>\u2013 \u0414\u0436\u043E\u043D, \u043F\u043E\u0447\u0435\u043C\u0443 \u0438 \u043A\u0430\u043A \u0434\u0430\u0432\u043D\u043E \u0440\u0435\u0448\u0438\u043B\u0438 \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u043E\u0435\u043A\u0442?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u044D\u0442\u0430 \u0438\u0434\u0435\u044F \u043D\u0435 \u043D\u0430\u0448\u0430, \u043F\u043E \u043C\u0438\u0440\u0443 \u0443\u0436\u0435 \u0434\u0430\u0432\u043D\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043C\u043D\u043E\u0433\u043E \u0442\u0430\u043A\u0438\u0445 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u0435\u043D\u044C. \u041C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E \u0443 \u043D\u0430\u0441 \u0441\u0430\u043C\u0430\u044F \u0432\u043E\u0441\u0442\u043E\u0447\u043D\u0430\u044F \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044F. \u0410 \u043A\u0430\u043A \u0434\u0430\u0432\u043D\u043E? \u041A\u0438\u0440\u0438\u043B\u043B, \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043D\u0430\u043C \u0443\u0436 \u043B\u0435\u0442?\xA0<em>(\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u0443\u0435\u0442\u0441\u044F \u0414\u0436\u043E\u043D \u0443 \u043E\u0434\u043D\u043E\u0433\u043E \u0438\u0437 \u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0434\u0435\u044F\u0442\u0435\u043B\u0435\u0439 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u0438)</em>.</p><p><strong>\u041A\u0438\u0440\u0438\u043B\u043B:</strong>\xA0\u0423\u0436\u0435 5 \u043B\u0435\u0442 \u0432 \u044D\u0442\u043E\u043C \u0433\u043E\u0434\u0443, \u0442\u043E \u0435\u0441\u0442\u044C \u043E\u0442\u043A\u0440\u044B\u043B\u0438\u0441\u044C \u043C\u044B \u0432 2013.</p><p><strong>\u2013 \u0421\u043B\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u043D\u0430\u0447\u0438\u043D\u0430\u0442\u044C?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong> \u041D\u0430\u043C \u043E\u0447\u0435\u043D\u044C \u043F\u043E\u043C\u043E\u0433\u043B\u043E \u041C\u0438\u043D\u0441\u043A\u043E\u0435 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0435\xA0\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435, \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0442\u043E\u0440\u043E\u043C \u0434\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430.\u0430\u0442\u043E\u0440\u043E\u043C \u0434\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430.</p><p><strong>\u2013 \u041C\u043E\u0436\u0435\u0442, \u043A\u0442\u043E-\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0443 \u0441\u043E \u0441\u043A\u0435\u043F\u0441\u0438\u0441\u043E\u043C?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u0427\u0435\u0441\u0442\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u044F, \u043A\u043E\u0433\u0434\u0430 \u0432\u043F\u0435\u0440\u0432\u044B\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0438\u043B\u0438 \u044D\u0442\u0443 \u0438\u0434\u0435\u044E \u043D\u0430 \u0432\u0435\u043B\u043E\u0444\u043E\u0440\u0443\u043C\u0435, \u043B\u044E\u0434\u0438 \u043E\u0442\u043D\u0435\u0441\u043B\u0438\u0441\u044C \u0441\u043A\u0435\u043F\u0442\u0438\u0447\u0435\u0441\u043A\u0438. \u0421\u0447\u0438\u0442\u0430\u043B\u0438, \u0447\u0442\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0431\u0443\u0434\u0443\u0442 \u043A\u0440\u0430\u0441\u0442\u044C, \u0447\u0442\u043E \u044D\u0442\u043E\u0442 \u043F\u0440\u043E\u0435\u043A\u0442 \u0432\u0440\u044F\u0434 \u043B\u0438 \u043D\u0430\u0431\u0435\u0440\u0435\u0442 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u043E\u0441\u0442\u044C, \u043D\u043E, \u043A\u0430\u043A \u0432\u0438\u0434\u0438\u0442\u0435, \u043C\u044B \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u043C.</p><p><strong>\u2013 \u0412 \u0423\u0441\u0442\u0430\u0432\u0435 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u0438 \u0435\u0441\u0442\u044C \u0442\u0430\u043A\u043E\u0439 \u043F\u0443\u043D\u043A\u0442: \xAB\u041F\u043E\u0447\u0438\u043D\u0438\u043B\u0438 \u2013 \u043E\u0441\u0442\u0430\u0432\u044C\u0442\u0435 \u0447\u0442\u043E-\u043D\u0438\u0431\u0443\u0434\u044C \u0432\u0437\u0430\u043C\u0435\u043D\xBB. \u0427\u0430\u0441\u0442\u043E \u043B\u0438 \u043B\u044E\u0434\u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0435\u043C\u0443?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong> \u041F\u0440\u0438\u043D\u0446\u0438\u043F \u0442\u0430\u043A\u043E\u0439 \u0435\u0441\u0442\u044C, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u043D\u043E \u043A\u0442\u043E \u043C\u043E\u0436\u0435\u0442, \u0442\u043E\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442, \u043D\u043E \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u043E\u0431\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0447\u0442\u043E-\u0442\u043E \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043D\u0435\u0442.</p><p><img src="'+o+'" alt=""></p><p><strong>\u2013 \u0410 \u0431\u044B\u0432\u0430\u043B\u0438 \u0441\u043B\u0443\u0447\u0430\u0438, \u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u0447\u0438\u043D\u0438\u043B\u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434, \u043D\u043E \u0441\u043E\u0431\u0438\u0440\u0430\u043B\u0438 \u043D\u043E\u0432\u044B\u0439 \u0438\u0437 \u0438\u043C\u0435\u044E\u0449\u0438\u0445\u0441\u044F \u0447\u0430\u0441\u0442\u0435\u0439 \u0432 \u0433\u0430\u0440\u0430\u0436\u0435?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u0414\u0430, \u0431\u044B\u043B\u0438 \u0441\u043B\u0443\u0447\u0430\u0438. \u041A \u043F\u0440\u0438\u043C\u0435\u0440\u0443, \u041A\u0438\u0440\u0438\u043B\u043B \u0438 \u0410\u043B\u0435\u043A\u0441\u0430\u043D\u0434\u0440\xA0<em>(\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u043C\u0443\u0436\u0447\u0438\u043D\u0443, \u0437\u0430\u043D\u044F\u0442\u043E\u0433\u043E \u043F\u043E\u0447\u0438\u043D\u043A\u043E\u0439 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0430)</em>\xA0\u0441\u043E\u0431\u0438\u0440\u0430\u043B\u0438, \u0438, \u043F\u043E-\u043C\u043E\u0435\u043C\u0443, \u0434\u0430\u0436\u0435 \u043D\u0435 \u043E\u0434\u0438\u043D \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434.</p><p><img src="'+n+'" alt=""></p><p><strong>\u2013 \u0410 \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u0435, \u043A\u0430\u043A \u044D\u0442\u043E \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043E \u0443 \u0412\u0430\u0441 \u043D\u0430 \u0441\u0430\u0439\u0442\u0435, \u043F\u0440\u043E\u0441\u043C\u043E\u0442\u0440\u044B \u0432\u0435\u043B\u043E\u0444\u0438\u043B\u044C\u043C\u043E\u0432 \u0438\u043B\u0438 \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong> \u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0432\u0435\u043B\u043E\u0444\u0438\u043B\u044C\u043C\u043E\u0432, \u0442\u043E \u0434\u0430\u0432\u043D\u043E \u0443\u0436\u0435 \u043D\u0435 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u043B\u0438 \u043F\u0440\u043E\u0441\u043C\u043E\u0442\u0440\u043E\u0432, \u0442\u0430\u043A \u043A\u0430\u043A \u043D\u0435 \u0441\u043E\u0432\u0441\u0435\u043C \u0443\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E \u0434\u0435\u043B\u0430\u0442\u044C \u0432 \u043D\u0430\u0448\u0435\u043C \u0433\u0430\u0440\u0430\u0436\u0435. \u0410 \u0432\u043E\u0442 \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B\u2026 \u041A\u0438\u0440\u0438\u043B\u043B, \u0443 \u043D\u0430\u0441 \u0434\u0430\u0432\u043D\u043E \u043D\u0435 \u0431\u044B\u043B\u043E \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u043E\u0432, \u043D\u0443\u0436\u043D\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u0442\u044C!\xA0<em>(\u0441\u043C\u0435\u0435\u0442\u0441\u044F \u0414\u0436\u043E\u043D)</em>\xA0\u0415\u0441\u043B\u0438 \u0431\u0435\u0437 \u0448\u0443\u0442\u043E\u043A, \u0442\u043E \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B \u043F\u043E \u0440\u0435\u043C\u043E\u043D\u0442\u0443 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0430 \u043E\u0447\u0435\u043D\u044C \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u0435. \u041D\u0430 \u043C\u043E\u0439 \u0432\u0437\u0433\u043B\u044F\u0434, \u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u043E \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u044C \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B \u043F\u043E \u043F\u0440\u043E\u043A\u043E\u043B\u0443 \u0448\u0438\u043D, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440. \u0412\u0435\u0434\u044C \u043C\u0430\u043B\u043E \u043A\u0442\u043E \u0437\u043D\u0430\u0435\u0442, \u043A\u0430\u043A \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0432 \u0442\u0430\u043A\u043E\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438. \u0410 \u0443 \u043C\u0435\u043D\u044F, \u043A \u043F\u0440\u0438\u043C\u0435\u0440\u0443, \u0435\u0441\u0442\u044C \u0442\u0430\u043A\u043E\u0439 \u043D\u0430\u0431\u043E\u0440 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432\xA0<em>(\u0414\u0436\u043E\u043D \u043F\u043E\u043A\u0430\u0437\u0430\u043B \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E \u0441\u043E\u0431\u0440\u0430\u043D\u043D\u044B\u0435 \u0437\u0430\u043F\u0430\u0441\u043A\u0443, \u0437\u0430\u043F\u043B\u0430\u0442\u043A\u0438, \u043B\u043E\u043F\u0430\u0442\u043A\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0439 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442)</em>.</p><p><strong>\u2013 \u0414\u0436\u043E\u043D, \u0430 \u0412\u044B \u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0435\u0441\u044C \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043E\u043C?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u041E\u0431\u044B\u0447\u043D\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u043D\u0430 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0435, \u043D\u043E \u0441 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C \u0441\u044B\u043D\u0430 \u041C\u0430\u0440\u043A\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u0441\u0435\u0439\u0447\u0430\u0441 \u0432\u0441\u0435\u0433\u043E 3 \u043C\u0435\u0441\u044F\u0446\u0430, \u043F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u043D\u0430\u0447\u0430\u0442\u044C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043E\u043C, \u0442\u0430\u043A \u043A\u0430\u043A \u0441 \u0442\u0430\u043A\u0438\u043C \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0438\u043C \u0435\u0449\u0435 \u043D\u0435\u043B\u044C\u0437\u044F \u043D\u0430 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434.</p><p><strong>\u2013 \u041C\u043E\u0436\u0435\u0442, \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u0442\u0435\u0441\u044C \u0443\u0447\u0430\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0432 \u0412\u0435\u043B\u043E\u043A\u0430\u0440\u043D\u0430\u0432\u0430\u043B\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u043E\u0439\u0434\u0435\u0442 12 \u043C\u0430\u044F?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u0421\u0430\u043C \u043D\u0435 \u0431\u0443\u0434\u0443, \u0430 \u0432\u043E\u0442 \u0436\u0435\u043D\u0430 \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044F. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434 \u2013 \u044D\u0442\u043E \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u0437\u043D\u0430\u043A\u043E\u043C\u0441\u0442\u0432, \u044D\u0442\u043E \u0436\u0438\u0432\u043E\u0435 \u043E\u0431\u0449\u0435\u043D\u0438\u0435. \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u0438\u043C\u0435\u043D\u043D\u043E \u043B\u044E\u0431\u043E\u0432\u044C \u043A \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0430\u043C \u0438 \u043F\u043E\u0437\u043D\u0430\u043A\u043E\u043C\u0438\u043B\u0430 \u043D\u0430\u0441 \u0441 \u0436\u0435\u043D\u043E\u0439. \u041C\u044B \u0443\u0447\u0430\u0441\u0442\u0432\u043E\u0432\u0430\u043B\u0438 \u0432 \u0437\u0430\u0435\u0437\u0434\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C 2-3 \u0434\u043D\u044F \u043A\u0430\u0442\u0430\u043B\u0438\u0441\u044C \u0438 \u043F\u043E\u0441\u0435\u0449\u0430\u043B\u0438 \u043D\u0435\u043E\u0431\u044B\u0447\u043D\u044B\u0435 \u0431\u0438\u0431\u043B\u0438\u043E\u0442\u0435\u043A\u0438. \u041A\u0441\u0442\u0430\u0442\u0438 \u0433\u043E\u0432\u043E\u0440\u044F, \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E\u0435 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0438 \u0441\u043F\u043E\u0440\u0442, \u0438 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0443. \u0422\u0430\u043A \u0432\u043E\u0442, \u0442\u0430\u043A \u0438 \u043F\u043E\u0437\u043D\u0430\u043A\u043E\u043C\u0438\u043B\u0438\u0441\u044C.</p><p><img src="'+g+'" alt=""></p><p><strong>\u2013 \u0412\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434 \u0438\u0433\u0440\u0430\u0435\u0442 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0432\u0430\u0436\u043D\u0443\u044E \u0440\u043E\u043B\u044C \u0432 \u0432\u0430\u0448\u0435\u0439 \u0436\u0438\u0437\u043D\u0438. \u0410 \u0432\u0441\u0435-\u0442\u0430\u043A\u0438, \u043C\u043D\u043E\u0433\u0438\u0435 \u043B\u0438 \u0437\u043D\u0430\u044E\u0442 \u0438 \u043F\u043E\u0441\u0435\u0449\u0430\u044E\u0442 \xAB\u0413\u0430\u0440\u0430\u0436 38\xBB?</strong></p><p><strong>\u0414\u0436\u043E\u043D:</strong>\xA0\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u044D\u0442\u043E \u0441\u0435\u0437\u043E\u043D\u043D\u043E\u0435 \u0434\u0435\u043B\u043E. \u0417\u0438\u043C\u043E\u0439 \u0442\u0443\u0442 \u043E\u0447\u0435\u043D\u044C \u0442\u0438\u0445\u043E, \u0430 \u0432 \u0441\u0435\u0437\u043E\u043D \u043C\u043E\u0436\u0435\u043C \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043F\u043E\u0447\u0442\u0438 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C. \u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u043C\u044B \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u0437\u0430\u043D\u0438\u043C\u0430\u043B\u0438\u0441\u044C \u043F\u0438\u0430\u0440\u043E\u043C, \u0430 \u0442\u0435\u043F\u0435\u0440\u044C \u043D\u0435 \u0441\u0442\u0440\u0435\u043C\u0438\u043C\u0441\u044F \u043F\u0440\u0438\u0432\u043B\u0435\u0447\u044C \u0438\u0437\u043B\u0438\u0448\u043D\u0435\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F: \u0432\u0435\u043B\u043E\u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0438 \u0441\u0430\u043C\u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0442 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u2013 \u0438 \u043A\u043E\u043C\u0443 \u043D\u0430\u0434\u043E, \u0442\u043E\u0442 \u043F\u0440\u0438\u0435\u0437\u0436\u0430\u0435\u0442.</p><p>\u0423\u0436\u0435 \u0441\u043F\u0443\u0441\u0442\u044F \u043C\u0438\u043D\u0443\u0442 40 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u0435\u043B\u043E\u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u043D\u0430 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u0435 \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0438\u0431\u0430\u0432\u0438\u043B\u043E\u0441\u044C. \u041B\u044E\u0434\u0438 \u043F\u0440\u0438\u0435\u0437\u0436\u0430\u043B\u0438 \u0441 \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430\u043C\u0438, \u0438 \u043E\u0434\u043D\u0438\u043C \u0438\u0437 \u0438\u043D\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u043D\u044B\u0445 \u043F\u043E\u043C\u043E\u0449\u043D\u0438\u043A\u043E\u0432 \u0431\u044B\u043B \u0430\u043A\u0442\u0438\u0432\u0438\u0441\u0442 \u041C\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430\xA0<strong>\u0410\u043B\u0435\u043A\u0441\u0430\u043D\u0434\u0440 \u0414\u0435\u0449\u0435\u043D\u043A\u043E</strong>\xA0\u2013 \u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 \u0410\u043B\u0435\u043A\u0441\u0430\u043D\u0434\u0440, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0430\u043C \u0441\u043E\u0431\u0440\u0430\u043B \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\xA0\u043D\u0430 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u0435 \u0438 \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435\u043C \u043A\u0430\u0442\u0430\u0435\u0442 \u043D\u0430 \u043D\u0435\u043C \u0443\u0436\u0435 \u0431\u043E\u043B\u044C\u0448\u0435 \u0433\u043E\u0434\u0430.</p><p><strong>\u041A\u0438\u0440\u0438\u043B\u043B \u041A\u0443\u0434\u0440\u0430\u0432\u0435\u0446</strong>\xA0\u0442\u043E\u0436\u0435 \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u043F\u043E\u043C\u043E\u0433\u0430\u043B \u0433\u043E\u0441\u0442\u044F\u043C \u0413\u0430\u0440\u0430\u0436\u0430, \u043D\u043E \u043D\u0430\u0448\u0435\u043B \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0443\u044E \u043C\u0438\u043D\u0443\u0442\u043A\u0443, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u043C\u044B\u0441\u043B\u044F\u043C\u0438 \u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432 \u0411\u0435\u043B\u0430\u0440\u0443\u0441\u0438.</p><p><img src="'+a+'" alt=""></p><p><strong>\u041A\u0438\u0440\u0438\u043B\u043B:</strong>\xA0\u041C\u043D\u0435 \u043A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u043C\u044B \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u043C\u0441\u044F \u043F\u043E \u043C\u043E\u0434\u0435\u043B\u0438, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u0445\u043E\u0436\u0430 \u0441 \u0435\u0432\u0440\u043E\u043F\u0435\u0439\u0441\u043A\u043E\u0439, \u043D\u043E, \u043A \u0441\u043E\u0436\u0430\u043B\u0435\u043D\u0438\u044E, \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043E\u0442\u0441\u0442\u0430\u0432\u0430\u043D\u0438\u0435\u043C. \u041D\u0430 \u0434\u0430\u043D\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 \u0441\u0442\u0430\u0440\u0430\u044E\u0442\u0441\u044F \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0432\u0435\u043B\u043E\u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0443, \u0443\u0434\u043E\u0431\u043D\u0443\u044E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0434\u043B\u044F \u0432\u0441\u0435\u0445. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u044D\u0442\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u043F\u043E\u0434\u044A\u0435\u043C\u043D\u0438\u043A\u043E\u0432 \u0434\u043B\u044F \u043B\u044E\u0434\u0435\u0439 \u0441 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044F\u043C\u0438, \u0437\u0432\u0443\u043A\u043E\u0432\u044B\u0445 \u043F\u0435\u0448\u0435\u0445\u043E\u0434\u043E\u0432 \u0434\u043B\u044F \u0441\u043B\u0430\u0431\u043E\u0432\u0438\u0434\u044F\u0449\u0438\u0445 \u043B\u044E\u0434\u0435\u0439. \u041A \u0441\u043B\u043E\u0432\u0443 \u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438: \u0414\u0436\u043E\u043D \u043E\u0447\u0435\u043D\u044C \u043B\u044E\u0431\u0438\u0442 \u0442\u0435\u043C\u0443 \u0438\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u0439, \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0442\u0432\u0435\u0440\u0434\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0431 \u043E\u0434\u043D\u043E\u0439 \u2013 \u0431\u0435\u0441\u043F\u0438\u043B\u043E\u0442\u043D\u044B\u0439 \u0430\u0432\u0442\u043E\u043C\u043E\u0431\u0438\u043B\u044C. \u0414\u0436\u043E\u043D, \u043A\u0430\u043A\u0438\u0435 \u0438\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u0438 \u043D\u0430\u0441 \u0436\u0434\u0443\u0442?</p><p><strong>\u0414\u0436\u043E\u043D:</strong> \u0411\u0435\u0441\u043F\u0438\u043B\u043E\u0442\u043D\u044B\u0439 \u0430\u0432\u0442\u043E\u043C\u043E\u0431\u0438\u043B\u044C!\xA0<em>(\u0412\u0441\u0435 \u0441\u043C\u0435\u044E\u0442\u0441\u044F)</em></p><p><img src="'+i+'" alt=""></p><p>\u041D\u0430 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044E \u0437\u0430\u0435\u0437\u0436\u0430\u044E\u0442 \u0441\u0430\u043C\u044B\u0435 \u0440\u0430\u0437\u043D\u044B\u0435 \u043B\u044E\u0434\u0438, \u043D\u0430\u043C \u043F\u043E\u0441\u0447\u0430\u0441\u0442\u043B\u0438\u0432\u0438\u043B\u043E\u0441\u044C \u0432\u0441\u0442\u0440\u0435\u0442\u0438\u0442\u044C \u043F\u0440\u0435\u0434\u0441\u0435\u0434\u0430\u0442\u0435\u043B\u044F \u041C\u0438\u043D\u0441\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u2013 \u041F\u0430\u0432\u043B\u0430 \u0413\u043E\u0440\u0431\u0443\u043D\u043E\u0432\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043C\u0438\u043B\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u0438\u043B\u0441\u044F \u043E\u0442\u0432\u0435\u0442\u0438\u0442\u044C \u043D\u0430 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u043E\u043F\u0440\u043E\u0441\u043E\u0432.</p><p><strong>\u2013 \u041F\u0430\u0432\u0435\u043B, \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u0447\u0430\u0441\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u044B \u043C\u0435\u0436\u0434\u0443 \u043F\u0435\u0448\u0435\u0445\u043E\u0434\u0430\u043C\u0438 \u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0438\u0441\u0442\u0430\u043C\u0438. \u041D\u0430 \u0412\u0430\u0448 \u0432\u0437\u0433\u043B\u044F\u0434, \u043A\u0430\u043A \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u044C \u0432\u0435\u043B\u043E\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0443 \u0443 \u043D\u0430\u0441 \u0432 \u0441\u0442\u0440\u0430\u043D\u0435?</strong></p><p><strong>\u041F\u0430\u0432\u0435\u043B:</strong> \u0415\u0441\u0442\u044C \u0440\u0430\u0437\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0432\u0435\u043B\u043E\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B. \u0412\u043E-\u043F\u0435\u0440\u0432\u044B\u0445, \u0447\u0430\u0441\u0442\u044C \u043F\u0440\u043E\u0431\u043B\u0435\u043C \u0440\u0435\u0448\u0438\u0442\u0441\u044F, \u0435\u0441\u043B\u0438 \u0431\u0443\u0434\u0435\u0442 \u043D\u0430\u043B\u0430\u0436\u0435\u043D\u0430 \u0445\u043E\u0440\u043E\u0448\u0430\u044F \u0432\u0435\u043B\u043E\u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430. \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u0434\u0430\u043D\u043D\u044B\u0439 \u0432\u043E\u043F\u0440\u043E\u0441 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0441\u0443\u0449\u043D\u044B\u043C \u0432 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u041C\u0412\u041E. \u0412\u043E-\u0432\u0442\u043E\u0440\u044B\u0445, \u043D\u0443\u0436\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u043B\u044E\u0434\u044F\u043C, \u043A\u0430\u043A\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u043C \u0432\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438 \u043F\u0435\u0448\u0435\u0445\u043E\u0434\u043E\u0432 \u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0438\u0441\u0442\u043E\u0432. \u0413\u043B\u0430\u0432\u043D\u043E\u0435, \u0447\u0442\u043E\u0431\u044B \u043B\u044E\u0434\u0438 \u043D\u0430\u0441 \u0441\u043B\u044B\u0448\u0430\u043B\u0438. \u0415\u0449\u0451 \u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u043E, \u043A\u0430\u043A \u043B\u044E\u0434\u0438 \u0432\u044B\u0445\u043E\u0434\u044F\u0442 \u0438\u0437 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u0430: \u043A\u0442\u043E-\u0442\u043E \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442 \u0433\u0440\u0443\u0431\u043E, \u0430 \u043A\u0442\u043E-\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0441 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435\u043C. \u0415\u0441\u043B\u0438 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0445 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u0445 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0432\u0435\u043B\u043E\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B, \u0442\u043E \u043F\u0435\u0447\u0430\u0442\u0430\u0435\u043C \u0431\u0443\u043A\u043B\u0435\u0442\u044B \u0434\u043B\u044F \u0448\u043A\u043E\u043B, \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u043C\u0441\u044F \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0442\u044C \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0435 \u0440\u043E\u043B\u0438\u043A\u0438 \u0441 \u043F\u0440\u043E\u0441\u0442\u044B\u043C\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C\u0438, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0431\u0443\u0434\u0435\u0442 \u043F\u0430\u0440\u0443 \u0431\u0438\u043B\u0431\u043E\u0440\u0434\u043E\u0432 \u043F\u043E \u0433\u043E\u0440\u043E\u0434\u0443.</p><p><strong>\u2013 \u041A\u0430\u043A \u0434\u0443\u043C\u0430\u0435\u0442\u0435, \u0430 \u043C\u043E\u0433\u0443\u0442 \u0432\u0432\u0435\u0441\u0442\u0438 \u0441\u0434\u0430\u0447\u0443 \u043F\u0440\u0430\u0432\u0438\u043B \u0434\u043B\u044F \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0438\u0441\u0442\u043E\u0432?</strong></p><p><strong>\u041F\u0430\u0432\u0435\u043B:</strong> \u0421\u043A\u043E\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043E, \u0442\u0430\u043A\u043E\u0433\u043E \u043D\u0435 \u0431\u0443\u0434\u0435\u0442, \u0438 \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0432 \u0434\u0430\u043D\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0431\u0443\u0434\u0435\u0442 \u043D\u0430\u0440\u0443\u0448\u0430\u0442\u044C\u0441\u044F \u041C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u0430\u044F \u0412\u0435\u043D\u0441\u043A\u0430\u044F \u043A\u043E\u043D\u0432\u0435\u043D\u0446\u0438\u044F, \u043A \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0411\u0435\u043B\u0430\u0440\u0443\u0441\u044C \u043F\u0440\u0438\u0441\u043E\u0435\u0434\u0438\u043D\u0438\u043B\u0430\u0441\u044C \u0435\u0449\u0451 \u0432 60-\u0445 \u0433\u043E\u0434\u0430\u0445. \u0414\u0430 \u0438 \u0432\u043E\u043E\u0431\u0449\u0435, \u043B\u0438\u0448\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0441\u043D\u0438\u0437\u044F\u0442 \u043E\u0433\u0440\u043E\u043C\u043D\u0443\u044E \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u043E\u0441\u0442\u044C \u043A \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u043E\u043C\u0443 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044E, \u0431\u0443\u043C \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043C\u044B \u0441\u0435\u0439\u0447\u0430\u0441 \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0435\u043C.</p><p><strong>\u2013 \u041A\u0430\u043A\u0438\u0435 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u044B\u0435 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0432 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u041C\u0412\u041E?</strong></p><p><strong>\u041F\u0430\u0432\u0435\u043B:</strong>\xA0\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0443 \u041C\u0412\u041E \xA0\u043C\u043D\u043E\u0433\u043E \u0437\u0430\u0434\u0430\u0447 \u043D\u0430 \u0431\u043B\u0438\u0436\u0430\u0439\u0448\u0438\u0435 1,5 \u0433\u043E\u0434\u0430. \u041A\u0430\u043A \u0443\u0436\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u043B, \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u043C \u043D\u0430\u0434 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435\u043C \u0443\u0434\u043E\u0431\u043D\u043E\u0439 \u0432\u0435\u043B\u043E\u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u044B. \u041D\u0430\u0441 \u0441\u043B\u044B\u0448\u0430\u0442, \u0447\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043D\u0435 \u0440\u0430\u0434\u043E\u0432\u0430\u0442\u044C. \u0423\u0436\u0435 \u043A\u0430\u043A \u043F\u043E\u043B\u0433\u043E\u0434\u0430 \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u043C \u0434\u0440\u0443\u0433\u0438\u043C \u0433\u043E\u0440\u043E\u0434\u0430\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u0432\u0435\u043B\u043E\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435. \u0410 \u0435\u0449\u0451 \u0432 \u0441\u043A\u043E\u0440\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0432\u044B\u0439\u0434\u0435\u0442 \u043F\u0435\u0440\u0432\u044B\u0439 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442.</p><p>\u041F\u0430\u0432\u0435\u043B \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0438\u043B \u0441\u0442\u0430\u0442\u044C \u0447\u043B\u0435\u043D\u0430\u043C\u0438 \u041C\u0412\u041E, \u0434\u043B\u044F \u0447\u0435\u0433\u043E \u043D\u0443\u0436\u043D\u043E \u043E\u043F\u043B\u0430\u0442\u0438\u0442\u044C \u0432\u0437\u043D\u043E\u0441 \u0432 \u0440\u0430\u0437\u043C\u0435\u0440\u0435 \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 1 \u0431\u0430\u0437\u043E\u0432\u043E\u0439 \u0432\u0435\u043B\u0438\u0447\u0438\u043D\u044B \u0438 \u0437\u0430\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0444\u043E\u0440\u043C\u0443\xA0<a href="http://bike.org.by/ru/membership" class="external-link" target="_blank" rel="noopener noreferrer">\u043D\u0430 \u0441\u0430\u0439\u0442\u0435</a>, \u043F\u043E\u0441\u043B\u0435 \u0447\u0435\u0433\u043E \u043C\u043E\u0436\u043D\u043E \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0447\u043B\u0435\u043D\u0441\u043A\u0443\u044E \u043A\u0430\u0440\u0442\u043E\u0447\u043A\u0443. \u0418, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u041F\u0430\u0432\u0435\u043B \u043D\u0435 \u0437\u0430\u0431\u044B\u0442\u044C &quot;\u043F\u043E\u043B\u0435\u0447\u0438\u0442\u044C&quot; \u0441\u0432\u043E\u0439 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434, \u0437\u0430 \u0447\u0435\u043C, \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u0438 \u043F\u0440\u0438\u0435\u0445\u0430\u043B \u0432 &quot;\u0413\u0430\u0440\u0430\u0436 38&quot;.</p><p>\u041F\u043E\u0441\u0435\u0442\u0438\u0442\u0435\u043B\u0435\u0439 \u0443 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u043B\u043E\u0441\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043E\u043B\u044C\u0448\u0435. \u0414\u0430\u0436\u0435 \u043F\u0440\u0438\u0435\u0445\u0430\u043B\u0438 \u0440\u0435\u0431\u044F\u0442\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0443\u0436\u0435 \u0443\u0441\u043F\u0435\u043B\u0438 \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0441\u0443\u0431\u0431\u043E\u0442\u043D\u0438\u0439 \u0412\u0435\u043B\u043E\u043A\u0430\u0440\u043D\u0430\u0432\u0430\u043B \u0438 \u0437\u0430\u0431\u0440\u0430\u0442\u044C \u0441\u0432\u043E\u0438 \u0438\u043C\u0435\u043D\u043D\u044B\u0435 \u043A\u0430\u0440\u0442\u043E\u0447\u043A\u0438.</p><p><img src="'+_+'" alt=""></p><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043C\u044B \u043D\u0430 \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u0435 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0447\u0438\u043D\u0438\u043B\u0438, \u0443\u0445\u043E\u0434\u0438\u0442\u044C \u043E\u0442\u0442\u0443\u0434\u0430 \u043D\u0435 \u0445\u043E\u0442\u0435\u043B\u043E\u0441\u044C: \u043E\u0431\u0449\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0440\u0435\u0431\u044F\u0442\u0430 \u0438 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u0430\u044F \u0430\u0442\u043C\u043E\u0441\u0444\u0435\u0440\u0430 \u0440\u0430\u0441\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442.</p><p>\u0412 \u043E\u0431\u0449\u0435\u043C, \u0412\u0435\u043B\u043E\u041A\u0443\u0445\u043D\u044F \u2013 \u044D\u0442\u043E \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E, \u0433\u0434\u0435 \u0412\u044B \u0441\u043C\u043E\u0436\u0435\u0442\u0435 \u0438 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434 \u043F\u043E\u0447\u0438\u043D\u0438\u0442\u044C, \u0438 \u043D\u043E\u0432\u044B\u0445 \u0437\u043D\u0430\u043A\u043E\u043C\u044B\u0445 \u043D\u0430\u0439\u0442\u0438, \u0438 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u043C\u0430\u0441\u0441\u0443 \u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u044D\u043C\u043E\u0446\u0438\u0439!</p><p>\u0410\u0432\u0442\u043E\u0440: \u0410\u043D\u0430\u0441\u0442\u0430\u0441\u0438\u044F \u041A\u043E\u043D\u0438\u043A, \u0436\u0443\u0440\u043D\u0430\u043B\u0438\u0441\u0442 <a href="http://onetimer.by/" class="external-link" target="_blank" rel="noopener noreferrer">OneTimer.by</a></p>',44),m=[l];function b(h,f,k,d,y,u){return e(),t("div",null,m)}var A=r(c,[["render",b]]);export{x as __pageData,A as default};
